import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormDisplay } from '../../../includes';
import { hirSettingStrings, hirSettingActions } from '../../HIRSettings/config';
import { HIRButton } from '../../Includes/Buttons';
import { getFormDisplayData } from '../../../includes/Forms/FormDisplay/functions';
import { appActions, alertAction } from '../../../../actions';
import { CircularProgress } from '@material-ui/core';


const style = theme => ({
    root: {
    }
})
class _HIRNewAppointment extends Component {
    constructor(props) {
        super(props);
        this.formConfig = [
            {name : "unit", label : "Unit", type : "select", options : [
        
            ]},
            {name : "date", label : "Date", type : "date"}
        ]
        this.state = {
            loading : false
        }
    }
    componentDidMount() {
        const {
            dispatch,
            [hirSettingStrings.settings] : settings
        } = this.props;
        if(!settings) hirSettingActions.getSettings()(dispatch);
    }
    onClick(){
        this.setState({loading : true});
        const {dispatch, createAppointment} = this.props;
        const data = getFormDisplayData(
            this.newAppointmentFormContext,
            (name, value, context)=>{
                const today = new Date();
                const appoint = new Date(value);
                const todaySum = Number(today.getFullYear() + String(today.getMonth()).padStart(2, "0") + String(today.getDate()).padStart(2, "0"));
                const appointSum = Number(appoint.getFullYear() + String(appoint.getMonth()).padStart(2, "0") + String(appoint.getDate()).padStart(2, "0"));
                
                if(!String(value).trim()){
                    appActions.showSnackbar(
                        alertAction.error(name+" can not be empty")
                    )(dispatch)
                    return false
                }
                if(name === 'date' && todaySum > appointSum){
                    appActions.showSnackbar(
                        alertAction.error("Appointment can not be in the past, select a future date")
                    )(dispatch)
                    return false;
                }
                return true;
            }
        )();
        if(data && createAppointment)
            createAppointment(data, this);
        else this.setState({loading : false});
    }
    createAptButton = ({loading}) => () => {
        return <HIRButton 
            disabled={loading}
            type="primary" onClick={this.onClick.bind(this)}>
            {loading && <CircularProgress style={{
                width : 30, height : 30
            }} color="secondary"/>}
            Create Appointment
        </HIRButton>
    }
    render() {
        const {
            classes, 
            [hirSettingStrings.settings] : settings,
            patient
        } = this.props;
        const {loading } = this.state;
        let lastName, firstName; 
        if(patient){
            const {myProfile} = patient;
            lastName = myProfile.lastName;
            firstName = myProfile.firstName;
        }
        if(settings){
            const revenueTypes = settings.find(item=>item.name === "units");
            if(revenueTypes){
                this.formConfig = [...this.formConfig.map(item=>{
                    if(item.name === "unit"){
                        item.options = revenueTypes.values.map(item=>({_id : item.name, name : item.value}))                        
                    }
                    return item;
                })]
            }
        }
        return (
            <div className={classes.root}>
                <FormDisplay
                    getContext={context=>this.newAppointmentFormContext = context}
                    header={lastName && "New Appointment for "+lastName+", "+firstName}
                    formName="newAppointment"
                    formConfig={this.formConfig}
                    footer={this.createAptButton({loading})}
                />
            </div>
        );
    }
}


_HIRNewAppointment.propTypes = {
    classes : PropTypes.object.isRequired,
    patient : PropTypes.object,
    createAppointment : PropTypes.func,
};
const mapStateToProps = ({hirSettingReducer}) => ({
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings],
})


export const HIRNewAppointment = connect(mapStateToProps)(withStyles(style)(_HIRNewAppointment));
export {HIRNewAppointment as default};