import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { IconButton, TextField } from '@material-ui/core';
import { ArrowBackIos, ArrowForwardIos } from '@material-ui/icons';
import { hirUtil } from '../../../../utils';
const style = theme => ({
    root: {
        
    },
    container : {
        display : "flex",
        justifyContent : "center",
        alignItems : "center",
    },
    icon : {
        color : hirUtil.getTheme().primary1
    },
    text : {
        textAlign : "center",
    }
})
class _DateController extends Component {
    state = {
        year : new Date().getFullYear()
    }
    componentDidMount() {
        const {year} = this.state;
        this.getComponentData(year);
    }    
    nextBtn(){
        let year = parseInt(this.state.year) + 1;
        this.setState({year});
        this.getComponentData(year);
    }
    prevBtn(){
        let year = parseInt(this.state.year) - 1;
        this.setState({year});
        this.getComponentData(year);
    }
    onChange(e){
        const year = parseInt(e.target.value);
        this.setState({year});
        this.getComponentData(year);
    }
    async getComponentData(year){
        const {component, patientId, dispatch} = this.props;
        const data = await component.getData(year, patientId, dispatch);
        this.setState({data});
    }
    render() {
        const {classes, component : Component} = this.props;
        const {year, data} = this.state;
        return (
            <div className={classes.root}>
                <div className={classes.container}>
                    <IconButton onClick={this.prevBtn.bind(this)}>
                        <ArrowBackIos fontSize="small" className={classes.icon}/>
                    </IconButton>
                    <TextField
                        margin="normal"
                        variant="outlined"
                        value={year}
                        inputProps={{
                            className :classes.text
                        }}
                        onChange={this.onChange.bind(this)}
                        label="Year"
                        placeholder="Year"/>
                    <IconButton onClick={this.nextBtn.bind(this)}>
                        <ArrowForwardIos fontSize="small" className={classes.icon}/>
                    </IconButton>
                </div>
                <Component
                    getContext={context=>this.componentContext = context} 
                    data={data}
                    year={year}/>
            </div>
        );
    }
}
_DateController.propTypes = {
    classes : PropTypes.object.isRequired,
    component : PropTypes.object,
    patientId : PropTypes.number,
};
export const DateController = withStyles(style)(_DateController);